// ---------------------------------------------------------------------------
// All programs
// ---------------------------------------------------------------------------
const programsData = [tiaProgram, tiaSummerProgram, tiaPoolProgram, tmdProgram];

// ---------------------------------------------------------------------------
// Seed
// ---------------------------------------------------------------------------
const seed = async ({ reuseConnection = false } = {}) => {
    if (!reuseConnection) {
        console.log('Connecting to MongoDB...');
        await mongoose.connect(process.env.DB_URL);
        console.log('Connected.\n');
    }

    // Validate: no lesson should have an empty muxPlaybackId
    const warnings = [];
    for (const prog of programsData) {
        for (const section of prog.sections) {
            for (const mod of section.modules || []) {
                for (const lesson of mod.lessons || []) {
                    if (!lesson.muxPlaybackId) {
                        warnings.push(`  [WARN] ${prog.id} > ${section.id} > ${mod.id} > ${lesson.id} has EMPTY muxPlaybackId`);
                    }
                }
            }
        }
    }

    if (warnings.length > 0) {
        console.log('=== MuxPlaybackId Validation Warnings ===');
        warnings.forEach((w) => console.log(w));
        console.log(`Total lessons with empty muxPlaybackId: ${warnings.length}`);
        console.log('(This is expected if NEXT_PUBLIC_MUX_IDS env var is not set)\n');
    } else {
        console.log('All lessons have a non-empty muxPlaybackId.\n');
    }

    // Idempotent diff-based apply: only $set fields that actually changed,
    // $push new lessons/instructions with createdAt = updatedAt = NOW.
    // Preserves timestamps of unmodified subdocs (fixes the "Actualizado"
    // badge ghost-noise the old $set-based seed produced on every run).
    const agg = await runDiff({ programsData, execute: true, verbose: true });
    console.log(`\nSeed complete. Total ops: ${agg.totalOps}, lessons touched: ${agg.totalLessonsTouched}`);

    if (!reuseConnection) {
        await mongoose.disconnect();
    }
};

module.exports = { seed, programsData };

if (require.main === module) {
    seed().catch((err) => {
        console.error('Seed failed:', err);
        process.exit(1);
    });
}
